def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            weight = 1 / (j ** 1.5)
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        if capacity < item * 1.2:
            score *= 1.3
        elif capacity < item * 1.5:
            score *= 1.1
        else:
            score *= 0.7
        if capacity % 3 == 0:
            score -= 0.15
        elif capacity % 5 == 0:
            score += 0.2
        else:
            score += 0.05
        if score < 0:
            score = 0
        if ratio > 0.8:
            for k in range(3):
                score += (0.05 * (k + 1)) / (capacity + 1)
        priorities[i] = score
    return priorities
